content = "import { useRef } from 'react';\nimport { useCanvasStore } from '../store/canvas';\nimport { useAuthStore } from '../store/auth';\n\nexport function useProductDrop(canvasId, containerRef) {\n  const addCard   = useCanvasStore(s => s.addCard);\n  const user      = useAuthStore(s => s.user);\n  const guestId   = useRef('guest-' + Math.random().toString(36).slice(2, 7));\n  const userId    = user?.id || guestId.current;\n\n  const onDragOver = (e) => {\n    e.preventDefault();\n    e.dataTransfer.dropEffect = 'copy';\n  };\n\n  const onDrop = (e) => {\n    e.preventDefault();\n    const raw = e.dataTransfer.getData('application/drawnbuy-product');\n    if (!raw) return;\n    let product;\n    try { product = JSON.parse(raw); } catch { return; }\n\n    const rect = containerRef.current?.getBoundingClientRect();\n    if (!rect) return;\n\n    const x = Math.max(0, e.clientX - rect.left - 80);\n    const y = Math.max(0, e.clientY - rect.top  - 60);\n\n    addCard(canvasId, {\n      id: Date.now().toString(),\n      product,\n      x,\n      y,\n      ownerId: userId,\n    });\n  };\n\n  return { onDragOver, onDrop };\n}\n"
os.makedirs(r"src\\hooks", exist_ok=True)
open(r"src\\hooks\\useProductDrop.js", "w", encoding="utf-8").write(content)
print("Done: src/hooks/useProductDrop.js")

content = 'import { useState, useRef, useEffect } from \'react\';\nimport { useProductDrop } from \'../hooks/useProductDrop\';\nimport { useCanvasStore } from \'../store/canvas\';\nimport { useAuthStore } from \'../store/auth\';\nimport CanvasOverlayLayer from \'./CanvasOverlayLayer\';\nimport CanvasChatPanel from \'./CanvasChatPanel\';\nimport { CHAT_MSGS } from \'../data\';\n\nconst EMOJIS = [\'😀\',\'😂\',\'🥰\',\'😍\',\'🤩\',\'😎\',\'🥳\',\'🎉\',\'🔥\',\'💯\',\'👏\',\'✨\',\'💜\',\'💛\',\'🩵\',\'🛍️\',\'🎨\',\'👟\',\'👗\',\'💄\',\'⌚\',\'📱\',\'💻\',\'🎮\',\'🏠\',\'🍕\',\'🛒\',\'💪\',\'🧸\',\'📚\'];\n\nexport default function CollabCanvas() {\n  const canvasRef = useRef(null);\n  const [tool, setTool] = useState(\'draw\');\n  const [color, setColor] = useState(\'#7c3aed\');\n  const [size, setSize] = useState(\'md\');\n  const [msgs, setMsgs] = useState(CHAT_MSGS);\n  const [chatInput, setChatInput] = useState(\'\');\n  const [emojiOpen, setEmojiOpen] = useState(false);\n  const [activeTab, setActiveTab] = useState(\'chat\');\n  const drawingRef = useRef(false); // sync ref — avoids React async state issue\n  const lastPos = useRef(null);\n  const msgsRef = useRef(null);\n\n  const colors = [\'#7c3aed\',\'#fbbf24\',\'#67e8f9\',\'#ef4444\',\'#22c55e\',\'#f97316\',\'#000000\',\'#ffffff\'];\n  const sizes = { sm: 2, md: 4, lg: 8 };\n\n  useEffect(() => {\n\n    if (msgsRef.current) msgsRef.current.scrollTop = msgsRef.current.scrollHeight;\n  }, [msgs]);\n\n  // Product drop + overlay\n  const canvasContainerRef = useRef(null);\n  const { onDragOver, onDrop } = useProductDrop(\'main-collab\', canvasContainerRef);\n  const addSticker = useCanvasStore(s => s.addSticker);\n  const user = useAuthStore(s => s.user);\n  const [showStickerPicker, setShowStickerPicker] = useState(false);\n  const STICKER_EMOJIS = [\'🔥\',\'❤️\',\'👍\',\'😍\',\'💯\',\'⭐\',\'🛒\',\'💰\',\'✅\',\'🎉\',\'🤩\',\'💅\'];\n  const dropSticker = (emoji) => {\n    addSticker(\'main-collab\', {\n      id: Date.now().toString(),\n      emoji,\n      x: 80 + Math.random() * 300,\n      y: 60 + Math.random() * 200,\n      ownerId: user?.id || \'guest\',\n    });\n    setShowStickerPicker(false);\n  };\n\n  const getPos = (e, canvas) => {\n    const r = canvas.getBoundingClientRect();\n    const scaleX = canvas.width / r.width;\n    const scaleY = canvas.height / r.height;\n    const src = e.touches ? e.touches[0] : e;\n    return { x: (src.clientX - r.left) * scaleX, y: (src.clientY - r.top) * scaleY };\n  };\n\n  const startDraw = e => {\n    const canvas = canvasRef.current;\n    if (!canvas) return;\n    e.preventDefault();\n    drawingRef.current = true;\n    const pos = getPos(e, canvas);\n    lastPos.current = pos;\n    const ctx = canvas.getContext(\'2d\');\n    ctx.beginPath();\n    ctx.moveTo(pos.x, pos.y);\n  };\n\n  const doDraw = e => {\n    if (!drawingRef.current) return; // sync check\n    const canvas = canvasRef.current;\n    const ctx = canvas.getContext(\'2d\');\n    const pos = getPos(e, canvas);\n    if (tool === \'erase\') {\n      ctx.globalCompositeOperation = \'destination-out\';\n      ctx.clearRect(pos.x - 12, pos.y - 12, 24, 24);\n    } else {\n      ctx.globalCompositeOperation = \'source-over\';\n      ctx.strokeStyle = color;\n      ctx.lineWidth = sizes[size];\n      ctx.lineCap = \'round\';\n      ctx.lineJoin = \'round\';\n      ctx.lineTo(pos.x, pos.y);\n      ctx.stroke();\n    }\n    lastPos.current = pos;\n  };\n\n  const endDraw = () => { drawingRef.current = false; };\n\n  const clearCanvas = () => {\n    const canvas = canvasRef.current;\n    if (canvas) canvas.getContext(\'2d\').clearRect(0, 0, canvas.width, canvas.height);\n  };\n\n  const sendMsg = () => {\n    if (!chatInput.trim()) return;\n    setMsgs(m => [...m, { name: \'You\', me: true, text: chatInput.trim(), time: new Date().toLocaleTimeString(\'en\',{hour:\'2-digit\',minute:\'2-digit\'}) }]);\n    setChatInput(\'\');\n  };\n\n  return (\n    <div id="collabSection" style={{\n      background: \'linear-gradient(135deg,#3b0764,#5b21b6)\',\n      padding: \'1.2rem 2rem 1.5rem\',\n      position: \'relative\',\n      overflow: \'hidden\',\n    }}>\n      <style>{`\n        @keyframes invpulse { 0%,100%{box-shadow:0 4px 20px rgba(249,115,22,.45)} 50%{box-shadow:0 6px 32px rgba(249,115,22,.8),0 0 0 8px rgba(249,115,22,.1)} }\n        @keyframes pulseLive2 { 0%,100%{opacity:1} 50%{opacity:.75} }\n        @keyframes tdot { 0%,60%,100%{transform:translateY(0)} 30%{transform:translateY(-4px)} }\n        @keyframes wwave { 0%,100%{transform:scaleY(1)} 50%{transform:scaleY(1.6)} }\n        @keyframes blinkdot { 0%,100%{opacity:1} 50%{opacity:.2} }\n        .collab-orb { position:absolute; top:-60px; right:-60px; width:260px; height:260px; border-radius:50%; background:radial-gradient(circle,rgba(103,232,249,.08),transparent 70%); pointer-events:none; }\n        .collab-inner { max-width:1200px; margin:0 auto; }\n        .collab-head { display:flex; flex-direction:row; align-items:center; justify-content:space-between; gap:1rem; flex-wrap:wrap; margin-bottom:.6rem; }\n        .invite-btn {\n          background:linear-gradient(135deg,#f59e0b,#f97316); color:#fff; border:none;\n          border-radius:10px; padding:8px 20px; font-family:\'Space Grotesk\',sans-serif;\n          font-size:13px; font-weight:800; cursor:pointer; animation:invpulse 2.5s infinite;\n          white-space:nowrap;\n        }\n        .invite-btn:hover { transform:translateY(-2px) scale(1.03); }\n        .live-count-badge {\n          background:rgba(34,197,94,.2); border:1px solid rgba(34,197,94,.4); color:#4ade80;\n          font-size:10px; font-weight:800; padding:2px 8px; border-radius:20px;\n          display:inline-flex; align-items:center; gap:4px;\n        }\n        .live-dot { width:6px; height:6px; border-radius:50%; background:#22c55e; animation:pulseLive2 1.5s infinite; display:inline-block; }\n        .collab-grid { display:grid; grid-template-columns:1fr 305px; gap:14px; }\n        .cv-panel { border:2px solid rgba(251,191,36,.4); border-radius:16px; overflow:hidden; display:flex; flex-direction:column; }\n        .cv-top { background:rgba(0,0,0,.3); padding:8px 12px; display:flex; align-items:center; gap:8px; }\n        .cv-tools { background:rgba(0,0,0,.25); padding:7px 10px; display:flex; align-items:center; gap:6px; flex-wrap:wrap; }\n        .t-chip {\n          background:rgba(255,255,255,.1); border:1px solid rgba(255,255,255,.15);\n          color:rgba(255,255,255,.8); border-radius:7px; padding:5px 10px; font-size:11px;\n          font-weight:700; cursor:pointer; font-family:inherit; transition:.1s;\n        }\n        .t-chip.on,.t-chip:hover { background:rgba(251,191,36,.22); border-color:#fbbf24; color:#fbbf24; }\n        .cv-area { background:#fff; min-height:480px; position:relative; flex:1; }\n        .cv-area canvas { position:absolute; inset:0; width:100%; height:100%; }\n        .cv-hint { position:absolute; inset:0; display:flex; align-items:center; justify-content:center; pointer-events:none; transition:opacity .4s; }\n        .chat-panel { background:rgba(0,0,0,.28); border-radius:16px; display:flex; flex-direction:column; overflow:hidden; border:1px solid rgba(255,255,255,.08); }\n        .ctabs { display:flex; border-bottom:1px solid rgba(255,255,255,.08); }\n        .ctab { flex:1; padding:.55rem; text-align:center; font-size:.72rem; font-weight:800; color:rgba(255,255,255,.4); cursor:pointer; border-bottom:2px solid transparent; transition:.15s; background:none; border-top:none; border-left:none; border-right:none; font-family:inherit; }\n        .ctab.on { color:#67e8f9; border-bottom-color:#67e8f9; }\n        .who-bar { padding:.4rem .75rem; border-bottom:1px solid rgba(255,255,255,.08); display:flex; gap:.35rem; align-items:center; flex-wrap:wrap; }\n        .who-pill { display:flex; align-items:center; gap:.22rem; background:rgba(255,255,255,.07); border:1px solid rgba(255,255,255,.1); border-radius:999px; padding:2px 7px; font-size:.65rem; color:rgba(255,255,255,.75); font-weight:600; }\n        .msgs { flex:1; overflow-y:auto; padding:.6rem; display:flex; flex-direction:column; gap:.45rem; max-height:380px; scrollbar-width:thin; scrollbar-color:rgba(255,255,255,.1) transparent; }\n        .mw { display:flex; flex-direction:column; max-width:90%; }\n        .mw.me { align-self:flex-end; align-items:flex-end; }\n        .mw.them { align-self:flex-start; align-items:flex-start; }\n        .mname { font-size:.58rem; color:rgba(255,255,255,.4); margin-bottom:2px; font-weight:700; text-transform:uppercase; }\n        .mbbl { padding:.4rem .65rem; border-radius:10px; font-size:.75rem; line-height:1.45; }\n        .mw.me .mbbl { background:rgba(251,191,36,.2); color:#fde68a; border-bottom-right-radius:3px; }\n        .mw.them .mbbl { background:rgba(103,232,249,.15); color:#a5f3fc; border-bottom-left-radius:3px; }\n        .mtime { font-size:.58rem; color:rgba(255,255,255,.25); margin-top:2px; }\n        .chat-inp { border-top:1px solid rgba(255,255,255,.08); padding:.55rem; display:flex; flex-direction:column; gap:.35rem; }\n        .cinp-row { display:flex; gap:.4rem; align-items:flex-end; }\n        .cinp { flex:1; background:rgba(255,255,255,.08); border:1px solid rgba(255,255,255,.12); border-radius:9px; padding:.42rem .65rem; color:#fff; font-size:.75rem; resize:none; outline:none; font-family:inherit; max-height:65px; }\n        .cinp::placeholder { color:rgba(255,255,255,.35); }\n        .cinp:focus { border-color:rgba(103,232,249,.4); }\n        .sbtn { background:#fbbf24; color:#3b0764; border:none; border-radius:8px; width:32px; height:32px; display:flex; align-items:center; justify-content:center; cursor:pointer; font-size:.85rem; font-weight:800; flex-shrink:0; }\n        .emoji-btn { background:rgba(255,255,255,.15); border:1.5px solid rgba(255,255,255,.3); border-radius:8px; padding:5px 10px; font-size:18px; cursor:pointer; transition:.15s; flex-shrink:0; }\n        .emoji-picker { position:absolute; bottom:100%; left:0; background:#fff; border:1.5px solid #ede9fe; border-radius:14px; padding:.7rem; box-shadow:0 8px 40px rgba(124,58,237,.25); z-index:9998; width:260px; max-height:200px; overflow-y:auto; }\n        .emoji-grid { display:grid; grid-template-columns:repeat(8,1fr); gap:2px; }\n        .ep-em { font-size:20px; cursor:pointer; padding:5px; border-radius:8px; text-align:center; transition:.1s; display:flex; align-items:center; justify-content:center; }\n        .ep-em:hover { background:#f4f0ff; transform:scale(1.2); }\n        @media(max-width:900px) { .collab-grid { grid-template-columns:1fr; } }\n      `}</style>\n\n      <div className="collab-orb" />\n\n      <div className="collab-inner">\n        {/* Header */}\n        <div className="collab-head">\n          <div>\n            <h2 style={{ fontSize: \'1.1rem\', fontWeight: \'800\', color: \'#fff\', display: \'flex\', alignItems: \'center\', gap: \'8px\', margin: 0 }}>\n              🎨 Collaborative Canvas\n              <span className="live-count-badge"><span className="live-dot" /> 247 drawing now</span>\n            </h2>\n            <p style={{ fontSize: \'.7rem\', color: \'rgba(255,255,255,.5)\', margin: \'3px 0 0\' }}>Draw together, find products, shop as a team</p>\n          </div>\n          <button className="invite-btn">🔗 Invite Friends &amp; Family</button>\n        </div>\n\n        {/* Grid */}\n        <div className="collab-grid">\n          {/* Canvas Panel */}\n          <div className="cv-panel">\n            <div className="cv-top">\n              <span style={{ background: \'#ef4444\', color: \'#fff\', fontSize: \'10px\', fontWeight: \'800\', padding: \'3px 9px\', borderRadius: \'20px\', display: \'flex\', alignItems: \'center\', gap: \'4px\' }}>\n                <span style={{ width: \'5px\', height: \'5px\', borderRadius: \'50%\', background: \'#fff\', animation: \'blinkdot 1s infinite\', display: \'inline-block\' }} /> LIVE\n              </span>\n              <div style={{ display: \'flex\', gap: \'4px\' }}>\n                {[\'#7c3aed\',\'#fbbf24\',\'#67e8f9\',\'#ef4444\',\'#22c55e\',\'#000\'].map((c, i) => (\n                  <div key={i} onClick={() => { setColor(c); setTool(\'draw\'); }} style={{ width: \'16px\', height: \'16px\', borderRadius: \'50%\', background: c, cursor: \'pointer\', border: `2px solid ${color===c?\'#fff\':\'transparent\'}`, transition: \'.12s\' }} />\n                ))}\n              </div>\n              <div style={{ display: \'flex\', gap: \'3px\', marginLeft: \'4px\' }}>\n                {[\'sm\',\'md\',\'lg\'].map(s => (\n                  <div key={s} onClick={() => setSize(s)} style={{ background: size===s?\'rgba(251,191,36,.22)\':\'rgba(255,255,255,.1)\', border: `1px solid ${size===s?\'#fbbf24\':\'rgba(255,255,255,.15)\'}`, borderRadius: \'5px\', width: \'26px\', height: \'22px\', display: \'flex\', alignItems: \'center\', justifyContent: \'center\', cursor: \'pointer\' }}>\n                    <span style={{ background: \'#fff\', borderRadius: \'50%\', display: \'block\', width: s===\'sm\'?\'4px\':s===\'md\'?\'7px\':\'10px\', height: s===\'sm\'?\'4px\':s===\'md\'?\'7px\':\'10px\' }} />\n                  </div>\n                ))}\n              </div>\n              <span style={{ marginLeft: \'auto\', color: \'rgba(255,255,255,.65)\', fontSize: \'12px\', fontWeight: \'600\' }}>Room: #spring2026</span>\n            </div>\n\n            <div className="cv-tools">\n              {[[\'draw\',\'✏️ Draw\'],[\'erase\',\'🧹 Erase\']].map(([t,l]) => (\n                <button key={t} className={`t-chip ${tool===t?\'on\':\'\'}`} onClick={() => setTool(t)}>{l}</button>\n              ))}\n              <button className="t-chip" onClick={clearCanvas}>Clear</button>\n              <div style={{ position: \'relative\' }}>\n                <button\n                  onClick={() => setShowStickerPicker(v => !v)}\n                  style={{ background:\'rgba(255,255,255,.15)\', border:\'1.5px solid #fbbf24\', borderRadius:8, padding:\'4px 10px\', fontSize:\'.75rem\', fontWeight:700, cursor:\'pointer\', color:\'#fff\' }}\n                >+ Sticker</button>\n                {showStickerPicker && (\n                  <div style={{ position:\'absolute\', top:\'110%\', left:0, background:\'#fff\', borderRadius:12, padding:8, boxShadow:\'0 4px 20px rgba(0,0,0,.2)\', display:\'flex\', gap:4, flexWrap:\'wrap\', width:220, zIndex:50, border:\'1.5px solid #fbbf24\' }}>\n                    {STICKER_EMOJIS.map(e => (\n                      <button key={e} onClick={() => dropSticker(e)} style={{ fontSize:22, background:\'none\', border:\'none\', cursor:\'pointer\', padding:4, borderRadius:6 }}>{e}</button>\n                    ))}\n                  </div>\n                )}\n              </div>\n              <button className="t-chip" style={{ marginLeft: \'auto\' }}>💾 Save</button>\n              <button className="t-chip">📤 Share</button>\n            </div>\n\n            <div className="cv-area" style={{ cursor: tool===\'erase\'?\'cell\':\'crosshair\' }}>\n              <div\n                  ref={canvasContainerRef}\n                  style={{ position: \'relative\', flex: 1, width: \'100%\', height: \'100%\' }}\n                  onDragOver={onDragOver}\n                  onDrop={onDrop}\n                >\n                  <canvas\n                ref={canvasRef}\n                width={1000}\n                height={600}\n                style={{ position: \'absolute\', inset: 0, width: \'100%\', height: \'100%\' }}\n                onMouseDown={startDraw}\n                onMouseMove={doDraw}\n                onMouseUp={endDraw}\n                onMouseLeave={endDraw}\n                onTouchStart={startDraw}\n                onTouchMove={doDraw}\n                onTouchEnd={endDraw}\n              />\n                  <CanvasOverlayLayer canvasId="main-collab" />\n                </div>\n              <div className="cv-hint">\n                <span style={{ fontSize: \'13px\', color: \'rgba(124,58,237,.2)\', fontWeight: \'600\' }}>✏️ Draw or drag a product here — friends see it live!</span>\n              </div>\n            </div>\n          </div>\n\n          {/* Chat Panel */}\n          <div className="chat-panel">\n            <div className="ctabs">\n              {[[\'chat\',\'💬 Chat\'],[\'products\',\'🛍️ Products\'],[\'rooms\',\'🚪 Rooms\']].map(([t,l]) => (\n                <button key={t} className={`ctab ${activeTab===t?\'on\':\'\'}`} onClick={() => setActiveTab(t)}>{l}</button>\n              ))}\n            </div>\n\n            {activeTab === \'chat\' && <>\n            <div className="who-bar">\n              <span style={{ fontSize: \'.62rem\', color: \'rgba(255,255,255,.4)\', fontWeight: \'700\' }}>In room:</span>\n              {[\'Anna 🟢\',\'Maja 🟢\',\'You 🟢\'].map(n => (\n                <span key={n} className="who-pill"><span style={{ width: \'5px\', height: \'5px\', borderRadius: \'50%\', background: \'#22c55e\', display: \'inline-block\' }} />{n}</span>\n              ))}\n            </div>\n\n            <div className="msgs" ref={msgsRef}>\n              {msgs.map((m, i) => (\n                <div key={i} className={`mw ${m.me ? \'me\' : \'them\'}`}>\n                  {!m.me && <div className="mname">{m.name}</div>}\n                  <div className="mbbl">{m.text}</div>\n                  <div className="mtime">{m.time}</div>\n                </div>\n              ))}\n            </div>\n\n            <div className="chat-inp" style={{ position: \'relative\' }}>\n              {emojiOpen && (\n                <div className="emoji-picker">\n                  <div className="emoji-grid">\n                    {EMOJIS.map(em => (\n                      <div key={em} className="ep-em" onClick={() => { setChatInput(v => v + em); setEmojiOpen(false); }}>{em}</div>\n                    ))}\n                  </div>\n                </div>\n              )}\n              <div className="cinp-row">\n                <button className="emoji-btn" onClick={() => setEmojiOpen(o => !o)}>😊</button>\n                <textarea\n                  className="cinp"\n                  placeholder="Message Anna & Maja… 😊"\n                  value={chatInput}\n                  rows={1}\n                  onChange={e => setChatInput(e.target.value)}\n                  onKeyDown={e => { if (e.key === \'Enter\' && !e.shiftKey) { e.preventDefault(); sendMsg(); } }}\n                />\n                <button className="sbtn" onClick={sendMsg}>→</button>\n              </div>\n            </div>\n            </>}\n            {activeTab === \'products\' && (\n              <div style={{ flex:1, display:\'flex\', flexDirection:\'column\', alignItems:\'center\', justifyContent:\'center\', color:\'rgba(255,255,255,.5)\', padding:\'1rem\', textAlign:\'center\' }}>\n                <div style={{ fontSize:\'2rem\', marginBottom:\'.5rem\' }}>🛍️</div>\n                <div style={{ fontWeight:700, marginBottom:\'.3rem\' }}>Drag products here</div>\n                <div style={{ fontSize:\'.8rem\' }}>Drag any product card from below onto the canvas</div>\n              </div>\n            )}\n            {activeTab === \'rooms\' && (\n              <div style={{ flex:1, display:\'flex\', flexDirection:\'column\', alignItems:\'center\', justifyContent:\'center\', color:\'rgba(255,255,255,.5)\', padding:\'1rem\', textAlign:\'center\' }}>\n                <div style={{ fontSize:\'2rem\', marginBottom:\'.5rem\' }}>🚪</div>\n                <div style={{ fontWeight:700, marginBottom:\'.3rem\' }}>Private Rooms</div>\n                <div style={{ fontSize:\'.8rem\', marginBottom:\'1rem\' }}>Draw and shop with specific friends</div>\n                <button onClick={() => window.location.href=\'/canvases\'} style={{ background:\'linear-gradient(90deg,#7c3aed,#5b21b6)\', color:\'#fff\', border:\'1.5px solid #fbbf24\', borderRadius:8, padding:\'8px 18px\', cursor:\'pointer\', fontWeight:700 }}>Open Rooms →</button>\n              </div>\n            )}\n          </div>\n        </div>\n      </div>\n    </div>\n  );\n}\n'
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\CollabCanvas.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/CollabCanvas.jsx")

content = 'import { useState, useRef, useEffect } from \'react\';\nimport { DRAG_PRODS } from \'../data\';\n\n// Extend drag prods to 33+ by repeating with variation\nconst ALL_PRODS = [\n  ...DRAG_PRODS,\n  {name:\'AirPods Pro 2\',    price:\'2 799 kr\',old:\'3 299 kr\',img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'-15%\'},\n  {name:\'IKEA KALLAX\',      price:\'649 kr\',  old:\'\',         img:\'https://placehold.co/300x300/7c3aed/white?text=Product\', deal:\'\'},\n  {name:\'KitchenAid Mixer\', price:\'5 299 kr\',old:\'6 499 kr\', img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'-20%\'},\n  {name:"Levi\'s 501 Jeans", price:\'899 kr\',  old:\'\',         img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'\'},\n  {name:\'Dyson V15 Vacuum\', price:\'6 499 kr\',old:\'8 990 kr\', img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'-28%\'},\n  {name:\'H&M Linen Blazer\', price:\'699 kr\',  old:\'\',         img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'\'},\n  {name:\'iPad Air M2\',      price:\'8 999 kr\',old:\'\',         img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'\'},\n  {name:\'Zara Maxi Dress\',  price:\'399 kr\',  old:\'599 kr\',   img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'-33%\'},\n  {name:\'Samsung 4K TV\',    price:\'7 999 kr\',old:\'9 990 kr\', img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'-20%\'},\n  {name:\'Nike Running Shoes\',price:\'1 199 kr\',old:\'\',        img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'\'},\n  {name:\'Vitamix Blender\',  price:\'5 890 kr\',old:\'7 490 kr\', img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'-21%\'},\n  {name:\'Louis Vuitton Bag\',price:\'12 900 kr\',old:\'\',        img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'\'},\n  {name:\'LEGO Technic Set\', price:\'1 299 kr\',old:\'1 599 kr\', img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'-19%\'},\n  {name:\'Kindle Paperwhite\',price:\'1 249 kr\',old:\'\',         img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'\'},\n  {name:\'GoPro HERO 12\',    price:\'4 299 kr\',old:\'4 990 kr\', img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'-14%\'},\n  {name:\'Nespresso Vertuo\', price:\'1 690 kr\',old:\'2 490 kr\', img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'-32%\'},\n  {name:\'Acne Studios Jeans\',price:\'3 200 kr\',old:\'\',        img:\'https://placehold.co/300x300/7c3aed/white?text=Product\',deal:\'\'},\n];\n\nexport default function DragStrip() {\n  const [sort, setSort] = useState(\'featured\');\n  const [autoRotate, setAutoRotate] = useState(true);\n  const rowRef = useRef(null);\n\n  const sorted = [...ALL_PRODS].sort((a, b) => {\n    if (sort === \'price-asc\') return parseInt(a.price.replace(/[^0-9]/g,\'\')) - parseInt(b.price.replace(/[^0-9]/g,\'\'));\n    if (sort === \'price-desc\') return parseInt(b.price.replace(/[^0-9]/g,\'\')) - parseInt(a.price.replace(/[^0-9]/g,\'\'));\n    if (sort === \'deals\') return (b.deal ? 1 : 0) - (a.deal ? 1 : 0);\n    return 0;\n  });\n\n  useEffect(() => {\n    if (!autoRotate) return;\n    const el = rowRef.current;\n    if (!el) return;\n    let frame;\n    const step = () => {\n      el.scrollLeft += 0.5;\n      if (el.scrollLeft >= el.scrollWidth - el.clientWidth) el.scrollLeft = 0;\n      frame = requestAnimationFrame(step);\n    };\n    frame = requestAnimationFrame(step);\n    return () => cancelAnimationFrame(frame);\n  }, [autoRotate]);\n\n  const scroll = dir => {\n    rowRef.current?.scrollBy({ left: dir * 400, behavior: \'smooth\' });\n  };\n\n  return (\n    <div style={{ overflow: \'hidden\', background: \'#3b0764\', borderTop: \'1px solid rgba(255,255,255,.08)\', padding: \'.85rem 2rem\' }}>\n      <style>{`\n        @keyframes dealPop { 0%,100%{transform:scale(1)} 50%{transform:scale(1.05)} }\n        .pc {\n          min-width:148px; background:rgba(255,255,255,.06); border:1.5px solid rgba(255,255,255,.1);\n          border-radius:12px; overflow:hidden; cursor:grab; transition:.22s; position:relative;\n          flex-shrink:0; user-select:none;\n        }\n        .pc:hover { border-color:rgba(251,191,36,.5); transform:translateY(-2px); }\n        .pc:active { cursor:grabbing; opacity:.7; }\n        .deal-badge { position:absolute; top:6px; left:6px; background:#ef4444; color:#fff; font-size:.58rem; font-weight:800; padding:1px 6px; border-radius:4px; animation:dealPop 2s infinite; }\n        .drag-hint { position:absolute; top:5px; right:5px; background:rgba(0,0,0,.6); border-radius:4px; padding:2px 5px; font-size:.58rem; color:#fbbf24; font-weight:700; }\n        .prow { display:flex; gap:.85rem; overflow-x:auto; padding-bottom:.4rem; scrollbar-width:none; }\n        .prow::-webkit-scrollbar { display:none; }\n        .pc-cart { flex:1; background:#7c3aed; color:#fff; border:none; border-radius:6px; padding:4px; font-size:.65rem; font-weight:700; cursor:pointer; font-family:inherit; }\n        .pc-wish { background:rgba(255,255,255,.08); border:1px solid rgba(255,255,255,.12); border-radius:6px; padding:3px 6px; cursor:pointer; font-size:.7rem; color:#fff; }\n      `}</style>\n\n      {/* Header */}\n      <div style={{ maxWidth: \'1200px\', margin: \'0 auto .6rem\', display: \'flex\', alignItems: \'center\', gap: \'.75rem\', justifyContent: \'space-between\', flexWrap: \'wrap\' }}>\n        <div style={{ display: \'flex\', alignItems: \'center\', gap: \'.75rem\' }}>\n          <span style={{ fontSize: \'.95rem\', fontWeight: \'800\', color: \'#fff\' }}>🛍️ Drag Products to Canvas</span>\n          <span style={{ display: \'inline-flex\', alignItems: \'center\', gap: \'.3rem\', background: \'rgba(251,191,36,.15)\', border: \'1px solid rgba(251,191,36,.3)\', borderRadius: \'999px\', padding: \'2px 10px\', fontSize: \'.68rem\', color: \'#fbbf24\', fontWeight: \'700\' }}>\n            ✋ Drag any product to your canvas\n          </span>\n          <span style={{ display: \'inline-flex\', alignItems: \'center\', gap: \'.3rem\', background: \'rgba(255,255,255,.08)\', border: \'1px solid rgba(255,255,255,.12)\', borderRadius: \'999px\', padding: \'2px 10px\', fontSize: \'.68rem\', color: \'rgba(255,255,255,.6)\', fontWeight: \'700\', cursor: \'pointer\' }}\n            onClick={() => setAutoRotate(a => !a)}>\n            {autoRotate ? \'⏸ Pause\' : \'▶ Auto-rotate\'}\n          </span>\n        </div>\n        <select\n          value={sort}\n          onChange={e => setSort(e.target.value)}\n          style={{ background: \'rgba(0,0,0,.4)\', color: \'#fbbf24\', border: \'2.5px solid #fbbf24\', borderRadius: \'9px\', padding: \'7px 28px 7px 14px\', fontSize: \'.82rem\', fontWeight: \'800\', cursor: \'pointer\', outline: \'none\', fontFamily: \'inherit\' }}\n        >\n          <option value="featured">⭐ Featured</option>\n          <option value="deals">🔥 Best Deals</option>\n          <option value="price-asc">💰 Price: Low to High</option>\n          <option value="price-desc">💎 Price: High to Low</option>\n        </select>\n      </div>\n\n      {/* Row */}\n      <div style={{ maxWidth: \'1200px\', margin: \'0 auto\', position: \'relative\' }}>\n        <div\n          className="prow"\n          ref={rowRef}\n          onMouseEnter={() => setAutoRotate(false)}\n          onMouseLeave={() => setAutoRotate(true)}\n        >\n          {sorted.map((p, i) => (\n            <div\n              key={i}\n              className="pc"\n              draggable\n              onDragStart={e => {\n                e.dataTransfer.setData(\'application/drawnbuy-product\', JSON.stringify({ name: p.name, price: p.price, img: p.img, url: p.url }));\n                e.dataTransfer.effectAllowed = \'copy\';\n              }}\n            >\n              {p.deal && <span className="deal-badge">{p.deal}</span>}\n              <span className="drag-hint">DRAG</span>\n              <img src={p.img} alt={p.name} style={{ width: \'100%\', height: \'100px\', objectFit: \'cover\', display: \'block\', pointerEvents: \'none\' }} loading="lazy" />\n              <div style={{ padding: \'.5rem\' }}>\n                <div style={{ fontSize: \'.72rem\', fontWeight: \'700\', color: \'#fff\', lineHeight: 1.3, marginBottom: \'.22rem\' }}>{p.name}</div>\n                <div>\n                  <span style={{ fontSize: \'.88rem\', fontWeight: \'800\', color: \'#fbbf24\' }}>{p.price}</span>\n                  {p.old && <span style={{ fontSize: \'.65rem\', color: \'rgba(255,255,255,.35)\', textDecoration: \'line-through\', marginLeft: \'.25rem\' }}>{p.old}</span>}\n                </div>\n                <div style={{ display: \'flex\', gap: \'.35rem\', marginTop: \'.4rem\' }}>\n                  <button className="pc-cart">🛒 Add</button>\n                  <button className="pc-wish">♡</button>\n                </div>\n              </div>\n            </div>\n          ))}\n        </div>\n      </div>\n\n      {/* Nav buttons */}\n      <div style={{ maxWidth: \'1200px\', margin: \'.4rem auto 0\', display: \'flex\', alignItems: \'center\', justifyContent: \'space-between\', padding: \'0 .5rem\' }}>\n        <button onClick={() => scroll(-1)} style={{ background: \'rgba(255,255,255,.08)\', border: \'1px solid rgba(255,255,255,.15)\', color: \'rgba(255,255,255,.7)\', padding: \'5px 14px\', borderRadius: \'20px\', cursor: \'pointer\', fontFamily: \'inherit\', fontSize: \'12px\', fontWeight: \'700\' }}>◀ Scroll back</button>\n        <span style={{ fontSize: \'11px\', color: \'rgba(255,255,255,.35)\', fontWeight: \'600\' }}>{ALL_PRODS.length} products</span>\n        <button onClick={() => scroll(1)} style={{ background: \'rgba(255,255,255,.08)\', border: \'1px solid rgba(255,255,255,.15)\', color: \'rgba(255,255,255,.7)\', padding: \'5px 14px\', borderRadius: \'20px\', cursor: \'pointer\', fontFamily: \'inherit\', fontSize: \'12px\', fontWeight: \'700\' }}>Scroll forward ▶</button>\n      </div>\n    </div>\n  );\n}\n'
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\DragStrip.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/DragStrip.jsx")

content = 'import { useState, useEffect } from \'react\';\nimport { CATS, HERO_ADS, DRAG_PRODS } from \'../data\';\n\nfunction SideAdPanel({ ads, timerPct }) {\n  return (\n    <div style={{ display: \'flex\', flexDirection: \'column\', gap: \'.5rem\' }}>\n      {ads.map((ad, i) => (\n        <div\n          key={i}\n          onClick={() => window.open(ad.url, \'_blank\')}\n          style={{ background: \'rgba(255,255,255,.7)\', border: \'1.5px solid #ede9fe\', borderRadius: \'12px\', overflow: \'hidden\', cursor: \'pointer\', transition: \'.2s\' }}\n          onMouseEnter={e => { e.currentTarget.style.borderColor = \'#7c3aed\'; e.currentTarget.style.transform = \'translateY(-2px)\'; }}\n          onMouseLeave={e => { e.currentTarget.style.borderColor = \'#ede9fe\'; e.currentTarget.style.transform = \'none\'; }}\n        >\n          <img src={ad.img} alt={ad.name} style={{ width: \'100%\', height: \'88px\', objectFit: \'cover\', display: \'block\' }} />\n          <div style={{ padding: \'.4rem .5rem\', background: \'#fff\' }}>\n            <div style={{ fontSize: \'.68rem\', fontWeight: \'700\', color: \'#1a0a3e\', lineHeight: 1.3 }}>{ad.name}</div>\n            <div style={{ fontSize: \'.78rem\', fontWeight: \'800\', color: \'#7c3aed\' }}>{ad.price}</div>\n          </div>\n        </div>\n      ))}\n      <div style={{ height: \'2px\', background: \'#ede9fe\', borderRadius: \'2px\', overflow: \'hidden\' }}>\n        <div style={{ height: \'100%\', background: \'#7c3aed\', width: `${timerPct}%`, transition: \'width .3s linear\' }} />\n      </div>\n    </div>\n  );\n}\n\nexport default function ProductSearchPanel() {\n  const [search, setSearch] = useState(\'\');\n  const [activeCat, setActiveCat] = useState(CATS[0].slug);\n  const [adIdx, setAdIdx] = useState(0);\n  const [timerPct, setTimerPct] = useState(0);\n\n  const leftAds  = [0,1,2].map(i => HERO_ADS[(adIdx + i) % HERO_ADS.length]);\n  const rightAds = [0,1,2].map(i => HERO_ADS[(adIdx + 3 + i) % HERO_ADS.length]);\n\n  useEffect(() => {\n    const interval = setInterval(() => {\n      setTimerPct(p => {\n        if (p >= 100) { setAdIdx(i => (i + 3) % HERO_ADS.length); return 0; }\n        return p + 1;\n      });\n    }, 80);\n    return () => clearInterval(interval);\n  }, []);\n\n  const catProducts = DRAG_PRODS.filter(p => {\n    const matchesSearch = search ? p.name.toLowerCase().includes(search.toLowerCase()) : true;\n    const matchesCat    = activeCat === \'all\' || !activeCat\n      ? true\n      : (p.cat || \'\').toLowerCase().includes(activeCat.toLowerCase()) ||\n        p.name.toLowerCase().includes(activeCat.toLowerCase());\n    return matchesSearch && matchesCat;\n  });\n\n  return (\n    <div id="pspSection" style={{\n      background: \'linear-gradient(135deg,#ede9fe,#f4f0ff)\',\n      padding: \'.85rem 1.5rem 1.2rem\',\n      borderTop: \'3px solid #7c3aed\',\n      borderBottom: \'2px solid #ede9fe\',\n      overflow: \'hidden\',\n      boxSizing: \'border-box\',\n    }}>\n      <style>{`\n        .psp-inner { width:100%; display:grid; grid-template-columns:140px 1fr 140px; gap:1rem; align-items:start; }\n        .psp-search-box { background:#fff; border:2.5px solid #7c3aed; border-radius:10px; padding:9px 14px; color:#1a0a3e; font-family:\'Space Grotesk\',sans-serif; font-size:14px; outline:none; width:100%; box-sizing:border-box; box-shadow:0 2px 12px rgba(124,58,237,.12); transition:.2s; }\n        .psp-search-box:focus { border-color:#5b21b6; box-shadow:0 2px 20px rgba(124,58,237,.2); }\n        .psp-search-box::placeholder { color:#9ca3af; }\n        .cat-chip { display:inline-flex; align-items:center; gap:4px; padding:5px 11px; border-radius:999px; cursor:pointer; font-size:11px; font-weight:700; white-space:nowrap; border:1.5px solid #e5e7eb; background:#fff; color:#6b7280; font-family:inherit; transition:.12s; }\n        .cat-chip.on, .cat-chip:hover { background:#7c3aed; border-color:#7c3aed; color:#fff; }\n        .psp-card {\n          background:#fff; border:1.5px solid #ede9fe; border-radius:12px; overflow:hidden;\n          cursor:grab; transition:.22s; position:relative; min-width:130px; flex-shrink:0; user-select:none;\n        }\n        .psp-card:hover { border-color:rgba(124,58,237,.5); transform:translateY(-3px); box-shadow:0 8px 24px rgba(124,58,237,.15); }\n        .psp-card:active { cursor:grabbing; }\n        .drag-badge { position:absolute; top:4px; right:4px; background:#7c3aed; border-radius:4px; padding:1px 6px; font-size:.55rem; color:#fff; font-weight:800; }\n        .psp-products { display:grid; display:flex; gap:.75rem; overflow-x:auto; padding-bottom:.35rem; scrollbar-width:thin; min-height:110px; align-items:flex-start; }\n        @media(max-width:960px) { .psp-inner { grid-template-columns:1fr !important; } .psp-side { display:none !important; } }\n        @media(max-width:600px) { .psp-products { grid-template-columns:repeat(2,1fr) !important; } }\n      `}</style>\n\n      <div className="psp-inner">\n        {/* Left Ads */}\n        <div className="psp-side">\n          <SideAdPanel ads={leftAds} timerPct={timerPct} />\n        </div>\n\n        {/* Main Panel */}\n        <div style={{ background: \'#fff\', border: \'2px solid #ede9fe\', borderRadius: \'16px\', padding: \'.9rem 1.1rem\', position: \'relative\', zIndex: 2 }}>\n          <div style={{ display: \'flex\', flexDirection: \'column\', gap: \'.45rem\', marginBottom: \'.65rem\' }}>\n            <div style={{ display: \'flex\', alignItems: \'center\', justifyContent: \'space-between\' }}>\n              <span style={{ fontSize: \'.88rem\', fontWeight: \'800\', color: \'#1a0a3e\' }}>🔍 Find &amp; drag products to your canvas</span>\n              <span style={{ fontSize: \'.68rem\', background: \'#ede9fe\', border: \'1px solid rgba(124,58,237,.2)\', borderRadius: \'999px\', padding: \'2px 9px\', color: \'#7c3aed\', fontWeight: \'700\' }}>✋ Drag to canvas · Click to open store</span>\n            </div>\n            <input\n              className="psp-search-box"\n              type="text"\n              placeholder="Search e.g. Nike, watch, H&M dress, iPhone..."\n              value={search}\n              onChange={e => setSearch(e.target.value)}\n            />\n          </div>\n\n          {/* Category chips */}\n          <div style={{ display: \'flex\', gap: \'.35rem\', overflowX: \'auto\', paddingBottom: \'.5rem\', scrollbarWidth: \'none\', marginBottom: \'.7rem\' }}>\n            {CATS.slice(0, 14).map(c => (\n              <button\n                key={c.slug}\n                className={`cat-chip ${activeCat === c.slug ? \'on\' : \'\'}`}\n                onClick={() => setActiveCat(c.slug)}\n              >{c.emoji} {c.name}</button>\n            ))}\n          </div>\n\n          {/* Products grid */}\n          <div className="psp-products">\n            {catProducts.map((p, i) => (\n              <div\n                key={i}\n                className="psp-card"\n                draggable\n                onDragStart={e => {\n                  e.dataTransfer.setData(\'application/drawnbuy-product\', JSON.stringify({ name: p.name, price: p.price, img: p.img, url: p.url }));\n                  e.dataTransfer.effectAllowed = \'copy\';\n                }}\n              >\n                <span className="drag-badge">DRAG</span>\n                <img src={p.img} alt={p.name} style={{ width: "100%", height: "78px", objectFit: "cover", display: "block", pointerEvents: "none" }} />\n                <div style={{ padding: \'.45rem\' }}>\n                  <div style={{ fontSize: \'.72rem\', fontWeight: \'700\', color: \'#1a0a3e\', lineHeight: 1.3, marginBottom: \'.2rem\' }}>{p.name}</div>\n                  <div style={{ fontSize: \'.88rem\', fontWeight: \'800\', color: \'#7c3aed\' }}>{p.price}</div>\n                  {p.old && <div style={{ fontSize: \'.65rem\', color: \'#9ca3af\', textDecoration: \'line-through\' }}>{p.old}</div>}\n                </div>\n              </div>\n            ))}\n          </div>\n        </div>\n\n        {/* Right Ads */}\n        <div className="psp-side">\n          <SideAdPanel ads={rightAds} timerPct={timerPct} />\n        </div>\n      </div>\n    </div>\n  );\n}\n'
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\ProductSearchPanel.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/ProductSearchPanel.jsx")

content = "import { useState, useRef } from 'react';\nimport { useCanvasStore } from '../store/canvas';\nimport { useAuthStore } from '../store/auth';\n\nconst safeOpen = (url) => {\n  if (!url) return;\n  const trusted = ['amazon.co.uk','amazon.com','ikea.com','zalando.com','nike.com','boots.com'];\n  try {\n    const host = new URL(url).hostname.replace('www.','');\n    if (trusted.some(d => host.endsWith(d))) window.open(url, '_blank', 'noopener,noreferrer');\n    else window.open('https://www.amazon.co.uk/s?k='+encodeURIComponent(url), '_blank', 'noopener,noreferrer');\n  } catch {}\n};\n\nexport default function ProductCard({ card, canvasId }) {\n  // Auto-size: mini canvas (mini-preview, hero-canvas) = 100px, full = 160px\n  const isMini = canvasId === 'mini-preview' || canvasId === 'hero-canvas';\n  const cardW  = isMini ? 100 : 160;\n  const imgH   = isMini ? 70  : 110;\n  const fontSize = isMini ? '.6rem' : '.75rem';\n  const priceSize = isMini ? '.7rem' : '.82rem';\n  const btnSize = isMini ? '.55rem' : '.65rem';\n  const moveCard   = useCanvasStore(s => s.moveCard);\n  const removeCard = useCanvasStore(s => s.removeCard);\n  const user       = useAuthStore(s => s.user);\n  const userId     = user?.id || '';\n  const isOwner    = card.ownerId === userId || card.ownerId?.startsWith('guest');\n\n  const dragStart = useRef(null);\n  const [pos, setPos] = useState({ x: card.x, y: card.y });\n\n  const onMouseDown = (e) => {\n    e.stopPropagation();\n    dragStart.current = { mx: e.clientX, my: e.clientY, x: pos.x, y: pos.y };\n    const onMove = (ev) => {\n      const nx = dragStart.current.x + (ev.clientX - dragStart.current.mx);\n      const ny = dragStart.current.y + (ev.clientY - dragStart.current.my);\n      setPos({ x: nx, y: ny });\n      moveCard(canvasId, card.id, nx, ny);\n    };\n    const onUp = () => {\n      window.removeEventListener('mousemove', onMove);\n      window.removeEventListener('mouseup', onUp);\n    };\n    window.addEventListener('mousemove', onMove);\n    window.addEventListener('mouseup', onUp);\n  };\n\n  return (\n    <div\n      onMouseDown={onMouseDown}\n      style={{\n        position: 'absolute',\n        left: pos.x,\n        top: pos.y,\n        width: cardW,\n        background: '#fff',\n        borderRadius: 12,\n        boxShadow: '0 4px 24px rgba(124,58,237,.25)',\n        border: '2px solid #fbbf24',\n        cursor: 'grab',\n        zIndex: 10,\n        pointerEvents: 'auto',\n        userSelect: 'none',\n        overflow: 'hidden',\n        transition: 'box-shadow .15s',\n      }}\n    >\n      <img\n        src={card.product.img}\n        alt={card.product.name}\n        style={{ width: '100%', height: imgH, objectFit: 'cover', display: 'block', pointerEvents: 'none' }}\n        onError={e => { e.target.style.background = '#f4f0ff'; e.target.style.display = 'none'; }}\n      />\n      <div style={{ padding: '8px 10px 8px' }}>\n        <div style={{ fontSize: '.75rem', fontWeight: 800, color: '#1a0a3e', marginBottom: 2, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>\n          {card.product.name}\n        </div>\n        <div style={{ fontSize: '.82rem', fontWeight: 800, color: '#fbbf24', marginBottom: 6 }}>\n          {card.product.price}\n        </div>\n        <div style={{ display: 'flex', gap: 4 }}>\n          <button\n            onClick={() => safeOpen(card.product.url)}\n            style={{ flex: 1, background: 'linear-gradient(90deg,#7c3aed,#5b21b6)', color: '#fff', border: '1.5px solid #fbbf24', borderRadius: 6, padding: '5px 0', fontSize: btnSize, fontWeight: 700, cursor: 'pointer' }}\n          >\n            Add to Cart\n          </button>\n          {isOwner && (\n            <button\n              onClick={() => removeCard(canvasId, card.id, userId)}\n              style={{ background: '#fee2e2', color: '#b91c1c', border: '1px solid #fca5a5', borderRadius: 6, padding: '5px 8px', fontSize: '.65rem', fontWeight: 700, cursor: 'pointer' }}\n            >\n              ✕\n            </button>\n          )}\n        </div>\n      </div>\n    </div>\n  );\n}\n"
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\ProductCard.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/ProductCard.jsx")

content = 'import { useState, useRef } from \'react\';\nimport { useCanvasStore } from \'../store/canvas\';\nimport CanvasOverlayLayer from \'./CanvasOverlayLayer\';\nimport VoiceRecorder from \'./VoiceRecorder\';\nimport AudioMessage from \'./AudioMessage\';\n\nexport default function MiniFloatingCanvas() {\n  // ALL hooks must be at the top — no exceptions\n  const canvasRef      = useRef(null);\n  const containerRef   = useRef(null);\n  const lastPos        = useRef(null);\n  const addCard        = useCanvasStore(s => s.addCard);\n\n  const [minimized,      setMinimized]      = useState(false);\n  const drawingRef = useRef(false);\n  const [tool,           setTool]           = useState(\'draw\');\n  const [destination,    setDestination]    = useState(\'everyone\');\n  const [pendingProduct, setPendingProduct] = useState(null);\n  const [showRoomPicker, setShowRoomPicker] = useState(false);\n  const [confirmMsg,     setConfirmMsg]     = useState(\'\');\n  const [miniAudios,     setMiniAudios]     = useState([]);\n\n  const MOCK_ROOMS = [\n    { id: \'room-1\', name: \'Family Shopping\', online: [\'Anna\', \'Maja\'], isOnline: true  },\n    { id: \'room-2\', name: \'My Wishlist\',     online: [],              isOnline: false },\n    { id: \'room-3\', name: \'Spring Fashion\',  online: [\'Erik\'],        isOnline: true  },\n  ];\n\n  const getPos = (e, canvas) => {\n    const r = canvas.getBoundingClientRect();\n    const scaleX = canvas.width / r.width;\n    const scaleY = canvas.height / r.height;\n    const src = e.touches ? e.touches[0] : e;\n    return { x: (src.clientX - r.left) * scaleX, y: (src.clientY - r.top) * scaleY };\n  };\n\n  const startDraw = e => {\n    e.preventDefault();\n    const canvas = canvasRef.current;\n    if (!canvas) return;\n    drawingRef.current = true;\n    const ctx = canvas.getContext(\'2d\');\n    const pos = getPos(e, canvas);\n    ctx.beginPath();\n    ctx.moveTo(pos.x, pos.y);\n    lastPos.current = pos;\n  };\n\n  const doDraw = e => {\n    if (!drawingRef.current) return;\n    const canvas = canvasRef.current;\n    const ctx = canvas.getContext(\'2d\');\n    const pos = getPos(e, canvas);\n    if (tool === \'erase\') {\n      ctx.globalCompositeOperation = \'destination-out\';\n      ctx.clearRect(pos.x - 10, pos.y - 10, 20, 20);\n    } else {\n      ctx.globalCompositeOperation = \'source-over\';\n      ctx.strokeStyle = \'#7c3aed\';\n      ctx.lineWidth = 3;\n      ctx.lineCap = \'round\';\n      ctx.lineJoin = \'round\';\n      ctx.lineTo(pos.x, pos.y);\n      ctx.stroke();\n    }\n    lastPos.current = pos;\n  };\n\n  const endDraw = () => { drawingRef.current = false; };\n\n  const clearCanvas = () => {\n    const canvas = canvasRef.current;\n    if (canvas) canvas.getContext(\'2d\').clearRect(0, 0, canvas.width, canvas.height);\n  };\n\n  const handleDrop = (e) => {\n    e.preventDefault();\n    const raw = e.dataTransfer.getData(\'application/drawnbuy-product\');\n    if (!raw) return;\n    let product;\n    try { product = JSON.parse(raw); } catch { return; }\n\n    if (destination === \'everyone\') {\n      const cardId = Date.now().toString();\n      addCard(\'main-collab\', {\n        id: cardId, product,\n        x: 80 + Math.random() * 250,\n        y: 60 + Math.random() * 180,\n        ownerId: \'mini-guest\',\n      });\n      addCard(\'mini-preview\', {\n        id: cardId + \'-preview\', product,\n        x: 10 + Math.random() * 80,\n        y: 10 + Math.random() * 60,\n        ownerId: \'mini-guest\',\n      });\n      setConfirmMsg(\'Added to main canvas!\');\n      setTimeout(() => setConfirmMsg(\'\'), 2500);\n    } else {\n      setPendingProduct(product);\n      setShowRoomPicker(true);\n    }\n  };\n\n  const dropToRoom = (room) => {\n    if (!pendingProduct) return;\n    addCard(room.id, {\n      id: Date.now().toString(), product: pendingProduct,\n      x: 60 + Math.random() * 160,\n      y: 40 + Math.random() * 120,\n      ownerId: \'mini-guest\',\n    });\n    setShowRoomPicker(false);\n    setPendingProduct(null);\n    setConfirmMsg(\'Added to \' + room.name + \'!\');\n    setTimeout(() => setConfirmMsg(\'\'), 2500);\n  };\n\n  const onMiniAudio = (url, dur) => setMiniAudios(m => [...m, { url, dur, id: Date.now() }]);\n\n  return (\n    <div style={{\n      position: \'fixed\', bottom: 20, right: 20, zIndex: 300,\n      filter: \'drop-shadow(0 8px 32px rgba(124,58,237,.35))\',\n    }}>\n      {/* Room picker popup */}\n      {showRoomPicker && (\n        <div style={{ position: \'absolute\', bottom: \'100%\', right: 0, marginBottom: 8, background: \'#fff\', borderRadius: 12, padding: 12, width: 230, boxShadow: \'0 8px 32px rgba(0,0,0,.25)\', border: \'1.5px solid #fbbf24\', zIndex: 500 }}>\n          <div style={{ fontSize: \'.82rem\', fontWeight: 800, color: \'#1a0a3e\', marginBottom: 8 }}>Choose a room</div>\n          {MOCK_ROOMS.map(room => (\n            <button key={room.id} onClick={() => dropToRoom(room)} style={{ width: \'100%\', display: \'flex\', alignItems: \'center\', gap: 8, padding: \'8px 10px\', borderRadius: 8, border: \'1px solid #f3f4f6\', background: \'#fafafa\', cursor: \'pointer\', marginBottom: 4, fontFamily: \'inherit\' }}>\n              <div style={{ width: 8, height: 8, borderRadius: \'50%\', background: room.isOnline ? \'#22c55e\' : \'#d1d5db\', flexShrink: 0 }}/>\n              <div style={{ flex: 1, textAlign: \'left\' }}>\n                <div style={{ fontSize: \'.78rem\', fontWeight: 700, color: \'#1a0a3e\' }}>{room.name}</div>\n                {room.online.length > 0 && <div style={{ fontSize: \'.62rem\', color: \'#9ca3af\' }}>{room.online.join(\', \')} online</div>}\n              </div>\n            </button>\n          ))}\n          <button onClick={() => { setShowRoomPicker(false); setPendingProduct(null); }} style={{ width: \'100%\', padding: \'6px\', borderRadius: 8, border: \'1px solid #f3f4f6\', background: \'#fff\', color: \'#9ca3af\', fontSize: \'.72rem\', cursor: \'pointer\', fontFamily: \'inherit\' }}>Cancel</button>\n        </div>\n      )}\n\n      <div style={{\n        width: 280, background: \'linear-gradient(135deg,#1e1b4b,#4c1d95)\',\n        borderRadius: 16, overflow: \'hidden\', border: \'1.5px solid rgba(255,255,255,.15)\',\n      }}>\n        {/* Header */}\n        <div style={{ display: \'flex\', alignItems: \'center\', gap: 6, padding: \'8px 12px\', borderBottom: \'1px solid rgba(255,255,255,.1)\' }}>\n          <div style={{ width: 8, height: 8, borderRadius: \'50%\', background: \'#ef4444\' }}/>\n          <span style={{ color: \'#fff\', fontWeight: 800, fontSize: \'.82rem\', flex: 1 }}>LIVE Mini Canvas</span>\n          <button onClick={clearCanvas} style={{ background: \'none\', border: \'none\', color: \'rgba(255,255,255,.5)\', cursor: \'pointer\', fontSize: \'.75rem\' }}>✕ Clear</button>\n          <button onClick={() => setMinimized(v => !v)} style={{ background: \'none\', border: \'none\', color: \'rgba(255,255,255,.5)\', cursor: \'pointer\', fontSize: \'.85rem\' }}>\n            {minimized ? \'▲\' : \'▼\'}\n          </button>\n        </div>\n\n        {!minimized && (\n          <>\n            {/* Destination toggle */}\n            <div style={{ display: \'flex\', gap: 4, padding: \'6px 8px\', borderBottom: \'1px solid rgba(255,255,255,.1)\' }}>\n              {[\'everyone\', \'rooms\'].map(opt => (\n                <button key={opt} onClick={() => setDestination(opt)} style={{\n                  flex: 1, padding: \'4px 0\', borderRadius: 6, border: \'1.5px solid\',\n                  borderColor: destination === opt ? \'#fbbf24\' : \'rgba(255,255,255,.15)\',\n                  background: destination === opt ? \'#fbbf24\' : \'transparent\',\n                  color: destination === opt ? \'#1a0a3e\' : \'rgba(255,255,255,.7)\',\n                  fontSize: \'.68rem\', fontWeight: 700, cursor: \'pointer\',\n                }}>\n                  {opt === \'everyone\' ? \'Everyone\' : \'My Rooms\'}\n                </button>\n              ))}\n            </div>\n\n            {/* Confirm message */}\n            {confirmMsg && (\n              <div style={{ background: \'#d1fae5\', color: \'#065f46\', fontSize: \'.7rem\', fontWeight: 700, padding: \'4px 8px\', textAlign: \'center\' }}>\n                {confirmMsg}\n              </div>\n            )}\n\n            {/* Canvas drop area */}\n            <div\n              ref={containerRef}\n              style={{ position: \'relative\', width: \'100%\' }}\n              onDragOver={(e) => e.preventDefault()}\n              onDrop={handleDrop}\n            >\n              <canvas\n                ref={canvasRef}\n                width={560} height={280}\n                style={{ width: \'100%\', height: 140, display: \'block\', cursor: tool === \'erase\' ? \'cell\' : \'crosshair\', background: \'rgba(255,255,255,.04)\' }}\n                onMouseDown={startDraw} onMouseMove={doDraw} onMouseUp={endDraw} onMouseLeave={endDraw}\n                onTouchStart={startDraw} onTouchMove={doDraw} onTouchEnd={endDraw}\n              />\n              <CanvasOverlayLayer canvasId="mini-preview" />\n              {/* Placeholder text */}\n              <div style={{ position: \'absolute\', top: \'50%\', left: \'50%\', transform: \'translate(-50%,-50%)\', pointerEvents: \'none\', textAlign: \'center\' }}>\n                <div style={{ fontSize: \'.68rem\', color: \'rgba(255,255,255,.2)\', fontWeight: 600 }}>✏️ Draw or drag a product here</div>\n              </div>\n            </div>\n\n            {/* Tool buttons */}\n            <div style={{ display: \'flex\', gap: 4, padding: \'6px 8px\', borderTop: \'1px solid rgba(255,255,255,.08)\' }}>\n              {[\'draw\', \'erase\'].map(t => (\n                <button key={t} onClick={() => setTool(t)} style={{\n                  flex: 1, padding: \'4px 0\', borderRadius: 6, border: \'1.5px solid\',\n                  borderColor: tool === t ? \'#fbbf24\' : \'rgba(255,255,255,.15)\',\n                  background: tool === t ? \'rgba(251,191,36,.15)\' : \'transparent\',\n                  color: tool === t ? \'#fbbf24\' : \'rgba(255,255,255,.6)\',\n                  fontSize: \'.68rem\', fontWeight: 700, cursor: \'pointer\',\n                }}>\n                  {t === \'draw\' ? \'✏️ Draw\' : \'⬜ Erase\'}\n                </button>\n              ))}\n              <button\n                onClick={() => document.getElementById(\'collabSection\')?.scrollIntoView({ behavior: \'smooth\' }) || (window.location.href = \'/#collabSection\')}\n                style={{ flex: 1, padding: \'4px 0\', borderRadius: 6, border: \'1.5px solid #fbbf24\', background: \'rgba(251,191,36,.15)\', color: \'#fbbf24\', fontSize: \'.68rem\', fontWeight: 700, cursor: \'pointer\' }}\n              >↗ Open Full</button>\n            </div>\n\n            {/* Audio playback */}\n            {miniAudios.length > 0 && (\n              <div style={{ padding: \'4px 8px\', borderTop: \'1px solid rgba(255,255,255,.1)\' }}>\n                {miniAudios.slice(-1).map(a => (\n                  <AudioMessage key={a.id} url={a.url} duration={a.dur} sender="You" time="" isMe={true}/>\n                ))}\n              </div>\n            )}\n\n            {/* Voice recorder */}\n            <div style={{ padding: \'4px 8px\', borderTop: \'1px solid rgba(255,255,255,.1)\' }}>\n              <VoiceRecorder canvasId="mini-canvas" onAudioReady={onMiniAudio} userName="You"/>\n            </div>\n          </>\n        )}\n      </div>\n    </div>\n  );\n}\n'
os.makedirs(r"src\\components", exist_ok=True)
